local typeXUIHyper = typeof(CS.YXUIHyper)
local typeXUIText = typeof(CS.YXUIText)

------------------------------------------------------------------
---@class UIHyperText
local UIHyperText = LxClass("UIHyperText", nil)
------------------------------------------------------------------

local hyperFormat ="<link=\"%d\"><u>%s</u></link>"

local singleFormat = "<link=\"%d\">%s</link>"

function UIHyperText:UIHyperText()
    self._index = 0
end



function UIHyperText:Create(tran,isTarget)
    isTarget = isTarget == nil and true or isTarget
    local uiHyper = tran:GetComponent(typeXUIHyper)
    if not uiHyper then
        uiHyper = tran.gameObject:AddComponent(typeXUIHyper)
    end
    self._uiHyper = uiHyper
    local xuitext = tran:GetComponent(typeXUIText)
    if xuitext then
        xuitext.raycastTarget = isTarget
    end
    local uiCamera = LGameUI.GetUICamera()
    self._uiHyper:SetCamera(uiCamera)
    self._uiHyper:SetHyperCb(function (key)
        if self._metadata then
            local data = self._metadata[key]
            if data then
                data.func(data.para)
            end
        end
    end)

    self._index = 0
    self._metadata ={}
end

--[[args=
{

   function func
   table para
}
--]]

function UIHyperText:AddHyper(text,args)

    local index = self._index+1
    self._index = index

    self._metadata[tostring(index)] = args
    --table.insert(self._metadata,args)
    --local index = #self._metadata

    local format= hyperFormat
    if string.find(text,"<u.->.-</u>") then ---不要重复加下划线
        format = singleFormat
    end

    local hyperText = string.format(format,index,text)
    return hyperText
end

function UIHyperText:AddHyperFun(args,key)
    local finalKey = nil
    if string.isempty(key) then
        local index = self._index + 1
        self._index = index
        finalKey = index
    else
        finalKey = key
    end

    self._metadata[tostring(finalKey)] = args
    --table.insert(self._metadata,args)
end

function UIHyperText:AddHyperSingle(text,args)
    local index = self._index+1
    self._index = index
    self._metadata[tostring(index)] = args


    --table.insert(self._metadata,args)
    --local index = #self._metadata
    local hyperText = string.format(singleFormat,index,text)
    return hyperText
end

function UIHyperText:Reset()
    self._index = 0
    self._metadata = {}
end

function UIHyperText:Destroy()
    table.removeall(self)
end




return UIHyperText